fn process<OM: OutputMode>(&mut self, i: I) -> crate::PResult<OM, I, Self::Output, Self::Error> {
    let mut res = OM::Output::bind(|| (self.init)());
    let input = i.clone();

    match self.parser.process::<OM>(input) {
      Err(Err::Error(_)) => Err(Err::Error(OM::Error::bind(|| {
