fn process<OM: OutputMode>(
    &mut self,
    mut input: I,
  ) -> crate::PResult<OM, I, Self::Output, Self::Error> {
    let mut count = 0;

    loop {
      let input_ = input.clone();
      let len = input.input_len();
      match self
        .parser
        .process::<OutputM<Check, Check, OM::Incomplete>>(input_)
