              count += 1;
            }

            Err(Err::Error(_)) => return Ok((input, OM::Output::bind(|| count))),
            Err(Err::Failure(e)) => return Err(Err::Failure(e)),
            Err(Err::Incomplete(i)) => return Err(Err::Incomplete(i)),
